<template>
  <div id="Create">
    <section class="chat_question-create">
      <div class="chat_question-form">
        <div class="form-title">
          <h1>{{ $t("ChatQuestion.Create.header") }}</h1>
        </div>
        <div class="lang-select-input">
          <v-tabs v-model="tab" color="primary" slider-color="primary">
            <v-tabs-slider color="primary"></v-tabs-slider>
            <v-tab
                :href="lang.key"
                v-for="lang in $t('ChatQuestion.Create.lang')"
                :key="lang.key"
                @click="checkTabLang(lang)"
            >
              {{ lang }}
            </v-tab>
          </v-tabs>
          <div class="tab-content">
            <v-tabs-items v-model="tab">
              <v-tab-item
                  v-for="i in $t('ChatQuestion.Create.lang')"
                  :key="i"
                  :value="i.key"
              >
                <div class="card-form">
                  <div class="form-content">
                    <v-form  v-model="valid" ref="form" lazy-validation>

                      <v-text-field
                          v-show="isLaoTab"
                          v-model="question"
                          :rules="[$myValidator.SimpleValidate($t('Validate.required'))]"
                          :label="$t('ChatQuestion.Create.form.question')"
                          outlined
                          required
                      ></v-text-field>


                      <v-text-field
                          v-show="isEngTab"
                          v-model="questionEng"
                          :rules="[$myValidator.SimpleValidate($t('Validate.required'))]"
                          :label="$t('ChatQuestion.Create.form.question')"
                          outlined
                          required
                      ></v-text-field>

                      <v-select
                          v-show="tab == 0"
                          :items="$t('ChatQuestion.itemOption')"
                          item-text="name"
                          item-value="id"

                          v-model="optionAnswer"
                          :label="$t('ChatQuestion.Create.form.category')"
                          @change="changeOptionAnswer"
                          outlined


                      ></v-select>


                      <v-text-field
                          v-show="isLaoTab"
                          v-model="answer"
                          v-if="optionAnswer===1"
                          :label="$t('ChatQuestion.Create.form.answer')"
                          outlined
                          required
                      ></v-text-field>

                      <v-text-field
                          v-show="isEngTab"
                          v-model="answerEng"
                          v-if="optionAnswer===1"
                          :label="$t('ChatQuestion.Create.form.answer')"
                          outlined
                          required
                      ></v-text-field>


                      <div v-show="isLaoTab" v-if="optionAnswer===2">



                        <v-row justify="end" v-show="previewImage !== null ">
                          <v-btn
                              class="mx-2"
                              fab
                              dark
                              small
                              color="error"
                              @click="removeImage"
                          >
                            <v-icon dark>
                              mdi-close
                            </v-icon>
                          </v-btn>
                        </v-row>
                        <div class="upload-image mt-3">

                          <div class="content" v-show="previewImage === null">
                            <i class="fas fa-plus-circle"></i>
                            <h3>{{ $t("Post.Create.form.picture") }}</h3>

                          </div>
                          <img class="image-files" :src="previewImage" v-show="previewImage !== null"/>

                          <input

                              type="file"
                              class="choose-file"
                              name="upload-image"
                              accept="image/*"
                              @change="UploadImage"
                          />
                        </div>



                      </div>

                      <div v-show="isEngTab" v-if="optionAnswer===2">

                        <v-row justify="end" v-show="previewImageEng !== null">
                          <v-btn
                              class="mx-2"
                              fab
                              dark
                              small
                              color="error"
                              @click="removeImageEng"
                          >
                            <v-icon dark>
                              mdi-close
                            </v-icon>
                          </v-btn>
                        </v-row>
                        <div class="upload-image mt-3">

                          <div class="content" v-show="previewImageEng === null">
                            <i class="fas fa-plus-circle"></i>
                            <h3>{{ $t("Post.Create.form.picture") }}</h3>

                          </div>
                          <img class="image-files" :src="previewImageEng" v-show="previewImageEng !== null"/>
                          <input

                              type="file"
                              class="choose-file"
                              name="upload-image"
                              accept="image/*"
                              @change="UploadImageEng"
                          />
                        </div>



                      </div>

                    </v-form>
                    <div class="form-actions">
                      <v-btn plain @click="reset" class="mx-5">{{
                          $t("ChatQuestion.Create.form.button.cancel")
                        }}</v-btn>
                      <v-btn :disabled="!valid" @click="submitForm" class="btn btn-create">
                        {{ $t("ChatQuestion.Create.form.button.save") }}</v-btn
                      >
                    </div>
                  </div>
                </div>
              </v-tab-item>
            </v-tabs-items>
          </div>
        </div>
      </div>
    </section>
  </div>
</template>

<script>
import {mapActions} from 'vuex'
export default {
  name: "Create",

  data() {
    return {
      chat_question_id:0,
      question:'',
      questionEng:'',
      answer:'',
      answerEng:'',
      isLaoTab:false,
      isEngTab:false,
      tab: null,

      valid:true,
      uploadImage:null,
      uploadImageEng:null,
      previewImage: null,
      previewImageEng: null,

      optionAnswer:1,

    };
  },

  created() {

      this.getChatQuestionOne({'chat_question_id':this.$route.params.chat_question_id}).then(res=>{
        console.log(res)
        if(res.success){
          this.loadDataToComponent(res)
        }
      })
    },

  mounted() {
    this.checkTabLang('ລາວ')
  },

  methods: {
    changeOptionAnswer(value){
      if(value == 1){
        this.removeImage();
        this.removeImageEng();
      }else{
        this.answer = null;
        this.answerEng = null;
      }
    },

    UploadImage(e) {

      const img = e.target.files[0];


      this.uploadImage=img
      const reader = new FileReader();
      reader.readAsDataURL(img);
      reader.onload = (e) => {

        this.previewImage=e.target.result;

      }


    },

    UploadImageEng(e) {

      const img = e.target.files[0];


      this.uploadImageEng=img
      const reader = new FileReader();
      reader.readAsDataURL(img);
      reader.onload = (e) => {

        this.previewImageEng=e.target.result;

      }
    },

    removeImage()
    {
      this.uploadImage = null;
      this.previewImage=null;
    },

    removeImageEng()
    {
      this.uploadImageEng = null;
      this.previewImageEng=null;
    },

    async convertURLtoFile (url) {
      const response = await fetch(url);
      const data = await response.blob();
      const filename = url.split("/").pop(); // url 구조에 맞게 수정할 것
      const metadata = { type: `image/jpeg` };
      return new File([data], filename, metadata);
    },

    loadDataToComponent(res){
      let data = res.data
      this.chat_question_id=data.id;
      this.question=data[0].question;
      this.questionEng=data[1].question;

      if(data[0].image_option){
        this.optionAnswer=2;
        const img=`http://25.10.235.85:7000/images/chat-questions/${data[0].answer}`;
        const imgEng=`http://25.10.235.85:7000/images/chat-questions/${data[1].answer}`;
        this.convertURLtoFile(img).then(
            res=>{
              console.log(res)
              const reader = new FileReader();
              reader.readAsDataURL(res);
              reader.onload = (e) => {

                this.previewImage=e.target.result;

              }
            }
        )

        this.convertURLtoFile(imgEng).then(
            res=>{
              console.log(res)
              const reader = new FileReader();
              reader.readAsDataURL(res);
              reader.onload = (e) => {

                this.previewImageEng=e.target.result;

              }
            }
        )

      }else{
        this.optionAnswer=1;
        this.answer=data[0].answer;
        this.answerEng=data[0].answer;
      }

    },

    checkTabLang(lang){
      console.log(lang)
      if(lang == 'ລາວ' ||lang== 'Lao'){
        this.isLaoTab = true
        this.isEngTab = false

      }else{
        this.isLaoTab = false
        this.isEngTab = true

      }
    },

    submitForm () {
      this.$refs.form[0].validate();
      if(this.$refs.form[0].validate()){

        this.updateChatQuestion({
          'chat_question_id':this.$route.params.chat_question_id,
          'question':this.question,
          'questionEng':this.question,
          'answer':this.answer,
          'answerEng':this.answerEng,

          'image':this.previewImage,
          'imageEng':this.previewImageEng

        })

        console.log('create successful')
      }else{
        console.log('can not create')
      }
    },
    reset(){
      this.$router.back();
      this.$refs.form[0].reset();
    },

    ...mapActions({
      getChatQuestionOne:'ChatQuestion/getChatQuestionOne',
      updateChatQuestion:'ChatQuestion/updateChatQuestion'
    })
  },
};
</script>

<style lang="scss" scoped>


.chat_question-form {
  .form-title {
    width: 100%;
    padding: 0.5rem 0;
    h1 {
      font-size: 1.5rem;
      font-weight: 400;
      text-transform: uppercase;
    }
  }

  .lang-select-input {
    width: 100%;
    padding: 1rem 0;

    .tab-content {
      width: 100%;
      padding: 2rem 0;

      .card-form {
        width: 100%;
        padding: 0.5rem;
        display: flex;
        justify-content: center;
        align-items: center;

        .form-content {
          width: 70%;

          .upload-image {
            width: 100%;
            height: 300px;
            border-radius: 0.3rem;
            position: relative;
            overflow: hidden;
            object-fit: cover;
            transition: all ease 0.5s;
            border: 1px solid $gray-color;

            .image {
              width: 100%;
              overflow: hidden;
              object-fit: cover;
            }
            .content {
              position: absolute;
              left: 0;
              right: 0;
              top: 45%;
              margin: auto;
              text-align: center;

              i.fa-plus-circle {
                font-size: 2rem;
                color: $black-color;
              }
            }
            .image-files{
              max-height: 100%;
              max-width: 100%;
              display: block;
              margin-left: auto;
              margin-right: auto;


            }
            .choose-file {
              position: absolute;
              left: 0;
              right: 0;
              top: 0;
              margin: auto;
              text-align: center;
              z-index: 1;
              width: 100%;
              height: 100%;
              cursor: pointer;
              outline: none;
              opacity: 0;
            }
          }

          .form-actions {
            width: 100%;
            padding: 1rem 0;
            display: flex;
            justify-content: flex-end;
            align-items: center;
          }
        }
      }
    }
  }
}
</style>

